#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int C[N], H[M];
        for (int i = 0; i < N; i++) {
            scanf("%d", &C[i]);
        }
        for (int i = 0; i < M; i++) {
            scanf("%d", &H[i]);
        }
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 1; j <= N - i; j++) {
                int match = 1;
                for (int k = 0; k < M; k++) {
                    if (C[i + k * j] != H[k]) {
                        match = 0;
                        break;
                    }
                }
                if (match) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

