        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int[] C = new int[N];
            int[] H = new int[M];
            for (int i = 0; i < N; i++) {
                C[i] = sc.nextInt();
            }
            for (int i = 0; i < M; i++) {
                H[i] = sc.nextInt();
            }
            int count = 0;
            for (int i = 0; i < N; i++) {
                for (int j = 1; j <= N - i; j++) {
                    int match = 1;
                    for (int k = 0; k < M; k++) {
                        if (C[i + k * j] != H[k]) {
